/**
 * @param {number} l
 * @param {number} r
 * @param {string} directions
 * @return {number}
 */
function solve(l, r, directions) {
    let goodIntegerCount = 0;

    for (let x = l; x <= r; x++) {
        // 1. Format x into a 16-digit string with leading zeros
        const xString = String(x).padStart(16, '0');

        // 2. Fill the 4x4 grid (Row-major order)
        const grid = Array(4).fill(0).map(() => Array(4).fill(0));
        for (let i = 0; i < 16; i++) {
            const digit = parseInt(xString[i]);
            const row = Math.floor(i / 4);
            const col = i % 4;
            grid[row][col] = digit;
        }

        // 3. Traverse the grid according to directions and record the sequence
        let row = 0;
        let col = 0;
        const sequence = [grid[row][col]];

        // We have 6 directions, leading to 6 more steps after the starting cell (total length 7)
        for (let i = 0; i < directions.length; i++) {
            const move = directions[i];
            if (move === 'D') {
                row += 1;
            } else if (move === 'R') {
                col += 1;
            }

            // The problem description implies the path continues even if it goes out of bounds,
            // but based on the examples, the movement is applied, and then the new cell's value is recorded.
            // We must ensure row and col stay within 0..3, although the problem doesn't explicitly state boundary checks
            // for the path traversal itself, only for the grid indexing.
            // Since directions is 3 D's and 3 R's, the maximum displacement is (3, 3).
            // Start (0, 0) + (3, 3) = (3, 3), which is exactly on the grid edge.

            // Ensure coordinates are valid for safety, though mathematically they should be if the grid is 4x4
            row = Math.min(3, Math.max(0, row));
            col = Math.min(3, Math.max(0, col));

            sequence.push(grid[row][col]);
        }

        // 4. Check if the sequence is non-decreasing
        let isGood = true;
        for (let i = 0; i < sequence.length - 1; i++) {
            if (sequence[i] > sequence[i + 1]) {
                isGood = false;
                break;
            }
        }

        if (isGood) {
            goodIntegerCount++;
        }
    }

    return goodIntegerCount;
}

